import React, { useState } from "react";

const projects = [
  {
    id: 1,
    title: "Gestion Immobilière",
    category: "Full-Stack",
    year: "2025",
    desc: "API REST sécurisée pour la gestion de biens immobiliers. Authentification JWT, gestion des rôles (admin/agent/client), upload de photos et système de recherche avancé.",
    tags: ["Node.js", "MongoDB", "Express", "JWT", "REST API"],
    accent: "#E8440A",
    icon: "🏠",
    github: "https://github.com/yosrabenhmidaa",
    featured: true,
  },
  {
    id: 2,
    title: "Auth System Sécurisé",
    category: "Backend",
    year: "2024",
    desc: "Système d'authentification complet avec JWT, réinitialisation de mot de passe par email via Nodemailer, cookies httpOnly et protection CSRF.",
    tags: ["Node.js", "JWT", "Nodemailer", "Cookies", "Express"],
    accent: "#ff6b3d",
    icon: "🔐",
    github: "https://github.com/yosrabenhmidaa",
    featured: true,
  },
  {
    id: 3,
    title: "App Web Symfony",
    category: "Backend",
    year: "2023",
    desc: "Application web MVC développée avec PHP Symfony. Architecture propre, gestion des entités Doctrine, formulaires validés et interface d'administration.",
    tags: ["PHP", "Symfony", "Doctrine", "XAMPP", "MVC"],
    accent: "#E8440A",
    icon: "⚙️",
    github: "https://github.com/yosrabenhmidaa",
    featured: false,
  },
  {
    id: 4,
    title: "Dashboard React",
    category: "Frontend",
    year: "2024",
    desc: "Interface d'administration moderne avec React et Redux. Tableaux de bord dynamiques, gestion d'état globale, appels API REST et design responsive.",
    tags: ["React", "Redux", "JavaScript", "REST API", "CSS"],
    accent: "#ff6b3d",
    icon: "📊",
    github: "https://github.com/yosrabenhmidaa",
    featured: false,
  },
];

const cats = ["Tous", "Full-Stack", "Backend", "Frontend"];

export default function Projects() {
  const [active, setActive] = useState("Tous");

  const filtered =
    active === "Tous"
      ? projects
      : projects.filter((p) => p.category === active);

  return (
    <section className="section" id="projects" style={{ background: "#111" }}>
      <style>{`
        .proj-filters {
          display: flex;
          gap: 8px;
          margin-bottom: 48px;
          flex-wrap: wrap;
        }
        .proj-filter-btn {
          padding: 8px 20px;
          border-radius: 30px;
          font-size: 0.72rem;
          font-weight: 500;
          letter-spacing: 0.5px;
          text-transform: uppercase;
          border: 1px solid rgba(255,255,255,0.1);
          background: none;
          color: rgba(255,255,255,0.4);
          cursor: none;
          transition: all .2s;
        }
        .proj-filter-btn:hover {
          color: #fff;
          border-color: rgba(255,255,255,0.25);
        }
        .proj-filter-btn.active {
          background: var(--o);
          border-color: var(--o);
          color: #fff;
        }

        .proj-grid {
          display: grid;
          grid-template-columns: repeat(2, 1fr);
          gap: 20px;
        }

        .proj-card {
          background: rgba(255,255,255,0.02);
          border: 1px solid rgba(255,255,255,0.07);
          border-radius: 20px;
          overflow: hidden;
          cursor: none;
          transition: border-color .3s, transform .3s;
          position: relative;
        }
        .proj-card:hover {
          border-color: rgba(232,68,10,0.3);
          transform: translateY(-4px);
        }
        .proj-card.featured {
          grid-column: span 1;
        }

        .proj-thumb {
          height: 200px;
          background: #0d0d0d;
          display: flex;
          align-items: center;
          justify-content: center;
          position: relative;
          overflow: hidden;
        }
        .proj-thumb-icon {
          font-size: 4rem;
          opacity: 0.15;
          transition: opacity .3s, transform .3s;
        }
        .proj-card:hover .proj-thumb-icon {
          opacity: 0.25;
          transform: scale(1.1);
        }
        .proj-thumb-gradient {
          position: absolute;
          inset: 0;
          background: radial-gradient(circle at 50% 50%, rgba(232,68,10,0.12), transparent 70%);
        }
        .proj-thumb-lines {
          position: absolute;
          inset: 0;
          background-image: repeating-linear-gradient(
            0deg,
            transparent,
            transparent 28px,
            rgba(255,255,255,0.02) 28px,
            rgba(255,255,255,0.02) 29px
          );
        }
        .proj-year-badge {
          position: absolute;
          top: 16px;
          right: 16px;
          font-size: 0.62rem;
          letter-spacing: 1px;
          color: var(--o);
          background: rgba(232,68,10,0.1);
          border: 1px solid rgba(232,68,10,0.2);
          border-radius: 20px;
          padding: 3px 10px;
        }

        .proj-body {
          padding: 24px 28px 28px;
        }
        .proj-cat {
          font-size: 0.62rem;
          letter-spacing: 2px;
          text-transform: uppercase;
          color: var(--o);
          margin-bottom: 8px;
        }
        .proj-title {
          font-family: 'Syne', sans-serif;
          font-weight: 700;
          font-size: 1.1rem;
          color: #fff;
          margin-bottom: 10px;
          letter-spacing: -0.3px;
        }
        .proj-desc {
          font-size: 0.76rem;
          color: rgba(255,255,255,0.4);
          line-height: 1.8;
          margin-bottom: 18px;
        }
        .proj-tags {
          display: flex;
          flex-wrap: wrap;
          gap: 6px;
          margin-bottom: 20px;
        }
        .proj-tag {
          font-size: 0.63rem;
          padding: 3px 9px;
          border-radius: 20px;
          background: rgba(255,255,255,0.04);
          border: 1px solid rgba(255,255,255,0.08);
          color: rgba(255,255,255,0.35);
        }
        .proj-footer {
          display: flex;
          align-items: center;
          gap: 12px;
          padding-top: 16px;
          border-top: 1px solid rgba(255,255,255,0.06);
        }
        .proj-link {
          display: inline-flex;
          align-items: center;
          gap: 6px;
          font-size: 0.72rem;
          color: rgba(255,255,255,0.4);
          text-decoration: none;
          cursor: none;
          transition: color .2s;
          font-weight: 500;
        }
        .proj-link:hover { color: var(--o); }
